SELECT * FROM sys_announcement


        AND title LIKE '%' || #{title} || '%'


        AND msg_category = #{msgCategory}


        AND send_status = #{sendStatus}


ORDER BY create_time DESC

    LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM sys_announcement


        AND title LIKE '%' || #{title} || '%'


        AND msg_category = #{msgCategory}


        AND send_status = #{sendStatus}

SELECT a.*,
COALESCE(s.read_flag, 0) as read_flag, s.read_time FROM sys_announcement a INNER JOIN sys_announcement_send s ON a.id = s.annt_id AND s.user_id = #{userId} WHERE a.send_status = 1 AND (a.start_time IS NULL OR a.start_time <= CURRENT_TIMESTAMP) AND (a.end_time IS NULL OR a.end_time >= CURRENT_TIMESTAMP)
AND a.msg_category = #{msgCategory}
AND s.read_flag = #{readFlag}
AND a.create_time >= #{startTime}::timestamp
AND a.create_time <= (#{endTime}::timestamp + INTERVAL '1 day')
ORDER BY a.create_time DESC
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM sys_announcement a
INNER JOIN sys_announcement_send s ON a.id = s.annt_id AND s.user_id = #{userId}
WHERE a.send_status = 1
  AND (a.start_time IS NULL OR a.start_time <= CURRENT_TIMESTAMP)
  AND (a.end_time IS NULL OR a.end_time >= CURRENT_TIMESTAMP)

    AND a.msg_category = #{msgCategory}



    AND s.read_flag = #{readFlag}



    AND a.create_time >= #{startTime}::timestamp


    AND a.create_time <= (#{endTime}::timestamp + INTERVAL '1 day')
